namespace sv_e4aab447921c4278b9fe1e5177661c95;

public record Channel(int Id, string Name, string Description, int UnreadCount);
public record Message(int Id, int ChannelId, string Author, string Content, DateTime SentAt, int? ReplyToId, List<Reaction> Reactions);
public record Reaction(string Emoji, List<string> Users);
public record ThreadSummary(int RootMessageId, int ReplyCount, DateTime LastReplyAt);

public interface IChatService
{
    Task<List<Channel>> GetChannelsAsync();
    Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take);
    Task<Message> SendMessageAsync(int channelId, string content, int? replyToId);
    Task<List<Message>> GetThreadAsync(int rootMessageId);
    Task AddReactionAsync(int messageId, string emoji);
    Task MarkChannelReadAsync(int channelId);
}

@namespace sv_e4aab447921c4278b9fe1e5177661c95.Components.Chat

<div class="channel-item @(IsActive ? "active" : "")" @onclick="HandleClick">
    <div class="channel-name"># @Channel.Name</div>
    <div class="channel-description">@Channel.Description</div>
    @if (Channel.UnreadCount > 0)
    {
        <span class="unread-badge">@Channel.UnreadCount</span>
    }
</div>

@code {
    [Parameter, EditorRequired]
    public Channel Channel { get; set; } = default!;

    [Parameter]
    public bool IsActive { get; set; }

    [Parameter]
    public EventCallback<int> OnSelected { get; set; }

    private async Task HandleClick()
    {
        await OnSelected.InvokeAsync(Channel.Id);
    }
}

@namespace sv_e4aab447921c4278b9fe1e5177661c95.Components.Chat

<div class="message-item" @onmouseenter="() => _showActions = true" @onmouseleave="() => _showActions = false">
    <div class="message-header">
        <span class="message-author">@Message.Author</span>
        <span class="message-time">@FormatRelativeTime(Message.SentAt)</span>
    </div>
    <div class="message-content">@Message.Content</div>

    @if (Message.Reactions.Count > 0)
    {
        <div class="message-reactions">
            @foreach (var reaction in Message.Reactions)
            {
                <button class="reaction-badge" @onclick="() => HandleReaction(reaction.Emoji)">
                    @reaction.Emoji @reaction.Users.Count
                </button>
            }
        </div>
    }

    @if (ReplyCount > 0)
    {
        <button class="thread-link" @onclick="HandleReplyClick">
            @ReplyCount @(ReplyCount == 1 ? "reply" : "replies")
        </button>
    }

    @if (_showActions)
    {
        <div class="message-actions">
            <button class="action-btn" @onclick="HandleReplyClick" title="Reply in thread">💬</button>
            <button class="action-btn" @onclick="ToggleEmojiPicker" title="Add reaction">😀</button>
        </div>
    }

    @if (_showEmojiPicker)
    {
        <div class="emoji-picker">
            @foreach (var emoji in _commonEmojis)
            {
                <button class="emoji-option" @onclick="() => HandleReaction(emoji)">@emoji</button>
            }
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired]
    public Message Message { get; set; } = default!;

    [Parameter]
    public int ReplyCount { get; set; }

    [Parameter]
    public EventCallback<int> OnReplyClicked { get; set; }

    [Parameter]
    public EventCallback<(int MessageId, string Emoji)> OnReactionClicked { get; set; }

    private bool _showActions;
    private bool _showEmojiPicker;

    private static readonly string[] _commonEmojis = ["👍", "❤️", "😂", "🎉", "🤔", "👀"];

    private void ToggleEmojiPicker()
    {
        _showEmojiPicker = !_showEmojiPicker;
    }

    private async Task HandleReplyClick()
    {
        await OnReplyClicked.InvokeAsync(Message.Id);
    }

    private async Task HandleReaction(string emoji)
    {
        _showEmojiPicker = false;
        await OnReactionClicked.InvokeAsync((Message.Id, emoji));
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt;

        if (diff.TotalMinutes < 1) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d, yyyy");
    }
}

@namespace sv_e4aab447921c4278b9fe1e5177661c95.Components.Chat

<div class="message-input">
    <textarea @bind="_text" @bind:event="oninput" placeholder="@Placeholder"
              @onkeydown="HandleKeyDown" rows="2"></textarea>
    <button class="send-btn" @onclick="HandleSend" disabled="@string.IsNullOrWhiteSpace(_text)">
        @ButtonLabel
    </button>
</div>

@code {
    [Parameter]
    public string Placeholder { get; set; } = "Type a message…";

    [Parameter]
    public string ButtonLabel { get; set; } = "Send";

    [Parameter]
    public EventCallback<string> OnSend { get; set; }

    private string _text = string.Empty;

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await HandleSend();
        }
    }

    private async Task HandleSend()
    {
        if (string.IsNullOrWhiteSpace(_text))
            return;

        var message = _text.Trim();
        _text = string.Empty;
        await OnSend.InvokeAsync(message);
    }
}

@namespace sv_e4aab447921c4278b9fe1e5177661c95.Components.Chat

<div class="channel-sidebar">
    <div class="sidebar-header">
        <h3>Channels</h3>
    </div>
    <div class="channel-list">
        @foreach (var channel in Channels)
        {
            <ChannelItem Channel="channel"
                         IsActive="channel.Id == ActiveChannelId"
                         OnSelected="OnChannelSelected" />
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public List<Channel> Channels { get; set; } = [];

    [Parameter]
    public int ActiveChannelId { get; set; }

    [Parameter]
    public EventCallback<int> OnChannelSelected { get; set; }
}

@namespace sv_e4aab447921c4278b9fe1e5177661c95.Components.Chat

<div class="thread-panel">
    <div class="thread-header">
        <h4>Thread</h4>
        <button class="close-btn" @onclick="OnClose">✕</button>
    </div>

    @if (RootMessage is not null)
    {
        <div class="thread-root">
            <MessageItem Message="RootMessage"
                         OnReactionClicked="OnReactionClicked" />
        </div>

        <div class="thread-divider">
            <span>@ThreadMessages.Count @(ThreadMessages.Count == 1 ? "reply" : "replies")</span>
        </div>

        <div class="thread-messages">
            @foreach (var reply in ThreadMessages)
            {
                <MessageItem Message="reply"
                             OnReactionClicked="OnReactionClicked" />
            }
        </div>

        <MessageInput Placeholder="Reply in thread…"
                      ButtonLabel="Reply"
                      OnSend="OnSendReply" />
    }
</div>

@code {
    [Parameter, EditorRequired]
    public Message? RootMessage { get; set; }

    [Parameter]
    public List<Message> ThreadMessages { get; set; } = [];

    [Parameter]
    public EventCallback OnClose { get; set; }

    [Parameter]
    public EventCallback<string> OnSendReply { get; set; }

    [Parameter]
    public EventCallback<(int MessageId, string Emoji)> OnReactionClicked { get; set; }
}

