@namespace sv_e4aab447921c4278b9fe1e5177661c95.Components.Chat

<div class="message-input">
    <textarea @bind="_text" @bind:event="oninput" placeholder="@Placeholder"
              @onkeydown="HandleKeyDown" rows="2"></textarea>
    <button class="send-btn" @onclick="HandleSend" disabled="@string.IsNullOrWhiteSpace(_text)">
        @ButtonLabel
    </button>
</div>

@code {
    [Parameter]
    public string Placeholder { get; set; } = "Type a message…";

    [Parameter]
    public string ButtonLabel { get; set; } = "Send";

    [Parameter]
    public EventCallback<string> OnSend { get; set; }

    private string _text = string.Empty;

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await HandleSend();
        }
    }

    private async Task HandleSend()
    {
        if (string.IsNullOrWhiteSpace(_text))
            return;

        var message = _text.Trim();
        _text = string.Empty;
        await OnSend.InvokeAsync(message);
    }
}

