.chat-layout {
    height: 100vh;
    width: 100vw;
    overflow: hidden;
}

@page "/chat"
@layout ChatLayout
@rendermode InteractiveServer
@namespace sv_e4aab447921c4278b9fe1e5177661c95.Components.Chat
@inject IChatService ChatService

<PageTitle>Chat</PageTitle>

<div class="chat-container">
    <ChannelSidebar Channels="_channels"
                    ActiveChannelId="_activeChannelId"
                    OnChannelSelected="HandleChannelSelected" />

    <div class="message-area @(_isThreadOpen ? "" : "expanded")">
        @if (_activeChannel is not null)
        {
            <div class="area-header">
                <h3># @_activeChannel.Name</h3>
                <span class="area-description">@_activeChannel.Description</span>
            </div>

            <div class="message-list" @onscroll="HandleScroll">
                @if (_isLoadingMore)
                {
                    <div class="loading-indicator">Loading older messages…</div>
                }
                @foreach (var message in _messages)
                {
                    <MessageItem Message="message"
                                 ReplyCount="GetReplyCount(message.Id)"
                                 OnReplyClicked="HandleOpenThread"
                                 OnReactionClicked="HandleReaction" />
                }
            </div>

            <MessageInput Placeholder="Message #@_activeChannel.Name"
                          OnSend="HandleSendMessage" />
        }
        else
        {
            <div class="empty-state">
                <p>Select a channel to start chatting</p>
            </div>
        }
    </div>

    @if (_isThreadOpen && _threadRootMessage is not null)
    {
        <ThreadPanel RootMessage="_threadRootMessage"
                     ThreadMessages="_threadMessages"
                     OnClose="HandleCloseThread"
                     OnSendReply="HandleSendReply"
                     OnReactionClicked="HandleReaction" />
    }
</div>

@code {
    private List<Channel> _channels = [];
    private List<Message> _messages = [];
    private List<Message> _threadMessages = [];
    private Channel? _activeChannel;
    private Message? _threadRootMessage;
    private int _activeChannelId;
    private bool _isThreadOpen;
    private bool _isLoadingMore;
    private bool _hasMoreMessages = true;

    // Track reply counts per root message
    private Dictionary<int, int> _replyCounts = [];

    private const int PageSize = 30;

    protected override async Task OnInitializedAsync()
    {
        _channels = await ChatService.GetChannelsAsync();
        if (_channels.Count > 0)
        {
            await HandleChannelSelected(_channels[0].Id);
        }
    }

    private async Task HandleChannelSelected(int channelId)
    {
        _activeChannelId = channelId;
        _activeChannel = _channels.FirstOrDefault(c => c.Id == channelId);
        _messages = [];
        _replyCounts = [];
        _hasMoreMessages = true;
        _isThreadOpen = false;
        _threadRootMessage = null;
        _threadMessages = [];

        var messages = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
        _messages = messages;
        _hasMoreMessages = messages.Count == PageSize;

        BuildReplyCounts();

        await ChatService.MarkChannelReadAsync(channelId);

        // Update the channel's unread count locally
        var idx = _channels.FindIndex(c => c.Id == channelId);
        if (idx >= 0)
        {
            _channels[idx] = _channels[idx] with { UnreadCount = 0 };
        }
    }

    private async Task HandleScroll()
    {
        // Triggered on scroll; load more when user scrolls to top
        if (_isLoadingMore || !_hasMoreMessages || _activeChannel is null)
            return;

        _isLoadingMore = true;
        StateHasChanged();

        var older = await ChatService.GetMessagesAsync(_activeChannel.Id, _messages.Count, PageSize);
        _hasMoreMessages = older.Count == PageSize;
        _messages.InsertRange(0, older);
        BuildReplyCounts();

        _isLoadingMore = false;
    }

    private async Task HandleSendMessage(string content)
    {
        if (_activeChannel is null) return;

        var sent = await ChatService.SendMessageAsync(_activeChannel.Id, content, null);
        _messages.Add(sent);
    }

    private async Task HandleOpenThread(int messageId)
    {
        _threadRootMessage = _messages.FirstOrDefault(m => m.Id == messageId);
        if (_threadRootMessage is null) return;

        _threadMessages = await ChatService.GetThreadAsync(messageId);
        _isThreadOpen = true;
    }

    private void HandleCloseThread()
    {
        _isThreadOpen = false;
        _threadRootMessage = null;
        _threadMessages = [];
    }

    private async Task HandleSendReply(string content)
    {
        if (_activeChannel is null || _threadRootMessage is null) return;

        var reply = await ChatService.SendMessageAsync(_activeChannel.Id, content, _threadRootMessage.Id);
        _threadMessages.Add(reply);

        // Update reply count
        _replyCounts[_threadRootMessage.Id] = _threadMessages.Count;
    }

    private async Task HandleReaction((int MessageId, string Emoji) args)
    {
        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);

        // Optimistic update: add reaction to the message locally
        UpdateReactionOnMessage(_messages, args.MessageId, args.Emoji);
        UpdateReactionOnMessage(_threadMessages, args.MessageId, args.Emoji);
    }

    private static void UpdateReactionOnMessage(List<Message> messages, int messageId, string emoji)
    {
        var idx = messages.FindIndex(m => m.Id == messageId);
        if (idx < 0) return;

        var msg = messages[idx];
        var existingReaction = msg.Reactions.FirstOrDefault(r => r.Emoji == emoji);
        if (existingReaction is not null)
        {
            if (!existingReaction.Users.Contains("You"))
                existingReaction.Users.Add("You");
        }
        else
        {
            msg.Reactions.Add(new Reaction(emoji, ["You"]));
        }
    }

    private void BuildReplyCounts()
    {
        _replyCounts.Clear();
        foreach (var msg in _messages.Where(m => m.ReplyToId is not null))
        {
            var rootId = msg.ReplyToId!.Value;
            _replyCounts.TryGetValue(rootId, out var count);
            _replyCounts[rootId] = count + 1;
        }
    }

    private int GetReplyCount(int messageId)
    {
        return _replyCounts.GetValueOrDefault(messageId);
    }
}

