    {
        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);

        // Optimistic update: add reaction to the message locally
        UpdateReactionOnMessage(_messages, args.MessageId, args.Emoji);
        UpdateReactionOnMessage(_threadMessages, args.MessageId, args.Emoji);
    }

    private static void UpdateReactionOnMessage(List<Message> messages, int messageId, string emoji)
    {
        var idx = messages.FindIndex(m => m.Id == messageId);
        if (idx < 0) return;

        var msg = messages[idx];
        var existingReaction = msg.Reactions.FirstOrDefault(r => r.Emoji == emoji);
        if (existingReaction is not null)
        {
            if (!existingReaction.Users.Contains("You"))
                existingReaction.Users.Add("You");
        }
        else
        {
            msg.Reactions.Add(new Reaction(emoji, ["You"]));
        }
    }

    private void BuildReplyCounts()
    {
        _replyCounts.Clear();
        foreach (var msg in _messages.Where(m => m.ReplyToId is not null))
        {
            var rootId = msg.ReplyToId!.Value;
            _replyCounts.TryGetValue(rootId, out var count);
            _replyCounts[rootId] = count + 1;
        }
    }

    private int GetReplyCount(int messageId)
    {
        return _replyCounts.GetValueOrDefault(messageId);
    }
}

