.channel-item {
    display: flex;
    flex-direction: column;
    padding: 0.6rem 1rem;
    cursor: pointer;
    border-left: 3px solid transparent;
    transition: background-color 0.15s;
    position: relative;
}

.channel-item:hover {
    background-color: rgba(255, 255, 255, 0.08);
}

.channel-item.active {
    background-color: rgba(255, 255, 255, 0.12);
    border-left-color: #5865f2;
}

.channel-name {
    font-weight: 600;
    font-size: 0.95rem;
    color: #fff;
}

.channel-description {
    font-size: 0.78rem;
    color: #8e9297;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
    margin-top: 0.1rem;
}

.unread-badge {
    position: absolute;
    right: 0.75rem;
