    align-items: center;
    padding: 0.4rem 1rem;
    font-size: 0.78rem;
    color: #72767d;
    font-weight: 600;
}

.thread-messages {
    flex: 1;
    overflow-y: auto;
    padding: 0.25rem 0;
}

