toolArgs.file_text:
.chat-container {
    display: flex;
    height: 100vh;
    width: 100%;
    overflow: hidden;
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
}

/* Sidebar: 20% width */
.chat-container > ::deep .channel-sidebar {
    flex: 0 0 20%;
    min-width: 200px;
}

/* Main message area */
.message-area {
    flex: 1 1 55%;
    display: flex;
    flex-direction: column;
    background: #fff;
    min-width: 0;
    overflow: hidden;
}

.message-area.expanded {
    flex: 1 1 80%;
}

/* Thread panel: 25% */
.chat-container > ::deep .thread-panel {
    flex: 0 0 25%;
    min-width: 280px;
}

.area-header {
    padding: 0.75rem 1rem;
    border-bottom: 1px solid #e3e5e8;
    background: #fff;
}

.area-header h3 {
    margin: 0;
    font-size: 1.05rem;
    font-weight: 700;
    color: #2e3338;
}

.area-description {
    font-size: 0.82rem;
    color: #72767d;
    margin-top: 0.1rem;
    display: block;
}

.message-list {
    flex: 1;
    overflow-y: auto;
    padding: 0.5rem 0;
}

.loading-indicator {
    text-align: center;
    padding: 0.75rem;
    color: #72767d;
    font-size: 0.85rem;
}

.empty-state {
    flex: 1;
    display: flex;
    align-items: center;
    justify-content: center;
    color: #72767d;
    font-size: 1.1rem;
}

